class DSU:
    def __init__(self):
        self.parent = {}

    def find(self, x):
        # lazily create a node as its own root
        if x not in self.parent:
            self.parent[x] = x
            return x
        # path compression
        root = x
        while self.parent[root] != root:
            root = self.parent[root]
        while self.parent[x] != root:
            self.parent[x], x = root, self.parent[x]
        return root

    def union(self, a, b):
        ra, rb = self.find(a), self.find(b)
        if ra != rb:
            self.parent[ra] = rb


def removeStones(stones):
    OFFSET = 10001  # columns get a disjoint id range from rows
    dsu = DSU()
    for x, y in stones:
        dsu.union(x, y + OFFSET)
    # count distinct components among touched nodes only
    roots = {dsu.find(node) for node in dsu.parent}
    return len(stones) - len(roots)


if __name__ == "__main__":
    tests = [
        ([[0,0],[0,1],[1,0],[1,2],[2,1],[2,2]], 5),
        ([[0,0],[0,2],[1,1],[2,0],[2,2]], 3),
        ([[0,0]], 0),                       # single stone -> remove 0
        ([[0,0],[0,1]], 1),                 # share row -> remove 1
        ([[0,0],[1,1]], 0),                 # isolated -> remove 0
        ([[0,0],[1,1],[2,2],[3,3]], 0),     # all isolated diagonal
        ([[0,0],[0,1],[0,2],[0,3]], 3),     # all same row
        ([[0,0],[10000,10000]], 0),         # max coords, isolated
        ([[0,1],[1,0]], 0),                 # offset-collision check: row1 vs col1
    ]
    all_ok = True
    for stones, expected in tests:
        got = removeStones(stones)
        ok = got == expected
        all_ok &= ok
        print(f"{'OK ' if ok else 'XX '} got={got} exp={expected} stones={stones}")

    # stress: 1000 stones all in one row -> answer 999
    big = [[0, c] for c in range(1000)]
    print("stress one row:", removeStones(big), "expected 999")
    print("ALL PASS" if all_ok else "FAILURE")
